#include <bits/stdc++.h>
using namespace std;
string a, res;
int len;
stack<char> uqe; 
stack<int> uqd;
int change(string x) {
	stringstream ss;
	ss << x;
	int ans;
	ss >> ans;
	return ans;
}
int f(char x) {
	if(x=='^') return 4;
	if(x=='*'||x=='/') return 3;
	if(x=='+'||x=='-') return 2;
	return 1;
}
int main() {
	cin >> a;
	len = a.size();
	for(int i=0; i<len; i++) {
        if(a[i]=='('&&a[i+1]==')') {
            uqd.push(0);
            res += "0 ";
            continue;
        }
        if(a[i]==')'&&a[i-1]=='(') continue;
		if(a[i]=='+'||a[i]=='-'||a[i]=='*'||a[i]=='/'||a[i]=='^') {
			while(!uqe.empty()&&f(a[i])<=f(uqe.top())) {
				if(uqe.top()!='(') {
					res.push_back(uqe.top()); 
					res += " ";
				}
				uqe.pop();
			}
			uqe.push(a[i]);
		}
		if(a[i]=='(') uqe.push(a[i]);
		if(a[i]>='0'&&a[i]<='9') {
			int it = i;
			while(a[it]>='0'&&a[it]<='9') it ++;
			string tmp = a.substr(i, it-i);
			res += (tmp+" ");
			i = it-1;
		}
		if(a[i]==')') {
			while(!uqe.empty()&&uqe.top()!='(') {
				res += uqe.top(); res += " ";
				uqe.pop();
			}
			uqe.pop();
		}
	}
	while(!uqe.empty()) {
		res.push_back(uqe.top()); res += " ";
		uqe.pop(); 
	}
	len = res.size();
	for(int i=0; i<len; i++) {
		if(res[i]>='0'&&res[i]<='9') {
			int st = i, ed = i;
			while(res[ed]>='0'&&res[ed]<='9') ed ++;
			string tmp = res.substr(st, ed-st);
			uqd.push(change(tmp));
			i = ed-1;
		} else if(res[i]=='+') {
			int l = uqd.top(); uqd.pop();
			int r = uqd.top(); uqd.pop();
			uqd.push(l+r);
		} else if(res[i]=='-') {
			int l = uqd.top(); uqd.pop();
			int r = uqd.top(); uqd.pop();
			uqd.push(r-l);
		} else if(res[i]=='*') {
			int l = uqd.top(); uqd.pop();
			int r = uqd.top(); uqd.pop();
			uqd.push(l*r);
		} else if(res[i]=='/') {
			int l = uqd.top(); uqd.pop();
			int r = uqd.top(); uqd.pop();
			uqd.push(r/l);
		} else if(res[i]=='^') {
			int l = uqd.top(); uqd.pop();
			int r = uqd.top(); uqd.pop();
			uqd.push(int(pow(r, l)));
		}
	}
	cout << uqd.top();
    return 0;
}
